query:
-- Deletar municípios que contêm números
DELETE FROM municipios WHERE nome_municipio REGEXP '[0-9]';

-- Deletar cidades que contêm números
DELETE FROM cidades WHERE nome_cidade REGEXP '[0-9]';

-- Deletar estados que contêm números
DELETE FROM estados WHERE nome_estado REGEXP '[0-9]' OR uf REGEXP '[0-9]';

